int main() {
    int width = 800;
    int height = 600;
    int max_iter = 100;

    fprintf(stderr, "Creating high-resolution image: %dx%d\n", width, height);
    fprintf(stderr, "This will be downsampled with ffmpeg after rendering\n");
    fprintf(stderr, "Rendering high-resolution image...\n\n");

    // PPM header
    printf("P3\n");
    printf("%d %d\n", width, height);
    printf("255\n");

    // Mandelbrot set rendering
    for (int y = 0; y < height; y++) {
        // Progress reporting
        if (y % 6 == 0) {
            double progress = (double)y / height * 100;
            fprintf(stderr, "Progress: %.1f%%\n", progress);
        }

        for (int x = 0; x < width; x++) {
            // Map pixel to complex plane
            double zx = 0;
            double zy = 0;
            double cx = (x - width/2.0) * 3.0/width;
            double cy = (y - height/2.0) * 3.0/height;

            int iter = 0;
            while (iter < max_iter) {
                double zx2 = zx*zx;
                double zy2 = zy*zy;
                if (zx2 + zy2 > 4.0) break;
                zy = 2*zx*zy + cy;
                zx = zx2 - zy2 + cx;
                iter++;
            }

            // Color based on iteration count
            if (iter == max_iter) {
                printf("0 0 0\n"); // Black for points in the set
            } else {
                // Colorful escape time algorithm
                int r = (iter * 10) % 256;
                int g = (iter * 20) % 256;
                int b = (iter * 30) % 256;
                printf("%d %d %d\n", r, g, b);
            }
        }
    }

    fprintf(stderr, "Progress: 100.0%%\n");
    fprintf(stderr, "Rendering complete\n");
    fprintf(stderr, "Wrote image to image.ppm\n");
    fprintf(stderr, "Done.\n");

    return 0;
}
